parameters.jsCode:
const body = $input.item.json.body;

const required = ['user_id', 'client_id', 'period_start', 'period_end'];
for (const key of required) {
  if (!body[key] || String(body[key]).trim().length === 0) {
    throw new Error(`Missing required field: ${key}`);
  }
}

// Validate date formats YYYY-MM-DD
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(body.period_start)) throw new Error('period_start must be in YYYY-MM-DD format');
if (!dateRegex.test(body.period_end)) throw new Error('period_end must be in YYYY-MM-DD format');

if (new Date(body.period_end) <= new Date(body.period_start)) {
  throw new Error('period_end must be after period_start');
}

return [{
  json: {
    user_id: body.user_id.trim(),
    client_id: body.client_id.trim(),
    period_start: body.period_start.trim(),
    period_end: body.period_end.trim()
  }
}];

const validated = $('Validate Input').item.json;
const kpis = $('Fetch Client KPIs').item.json;
const branding = $('Fetch User Branding').item.json;
const systemPrompt = $input.item.json.system_prompt;

// Safe defaults for branding
const logoUrl = branding.logo_url || '';
const primaryColor = branding.primary_color || '#1a1a2e';
const companyName = branding.company_name || 'Your Agency';
const brandVoice = branding.brand_voice
  ? (typeof branding.brand_voice === 'object' ? branding.brand_voice.summary || JSON.stringify(branding.brand_voice) : branding.brand_voice)
  : 'Professional, results-focused, direct';

// Safe defaults for KPIs
const safeKpis = {
  leads: Number(kpis.leads || 0),
  calls_booked: Number(kpis.calls_booked || 0),
  deals_closed: Number(kpis.deals_closed || 0),
  revenue: Number(kpis.revenue || 0),
  content_shipped: Number(kpis.content_shipped || 0)
};

// Derived metrics
const leadToCallRate = safeKpis.leads > 0
  ? ((safeKpis.calls_booked / safeKpis.leads) * 100).toFixed(1) + '%'
  : 'N/A';
const callToCloseRate = safeKpis.calls_booked > 0
  ? ((safeKpis.deals_closed / safeKpis.calls_booked) * 100).toFixed(1) + '%'
  : 'N/A';
const revenueFormatted = '$' + safeKpis.revenue.toLocaleString('en-US');

return [{
  json: {
    user_id: validated.user_id,
    client_id: validated.client_id,
    period_start: validated.period_start,
    period_end: validated.period_end,
    kpis: safeKpis,
    derived: {
      lead_to_call_rate: leadToCallRate,
      call_to_close_rate: callToCloseRate,
      revenue_formatted: revenueFormatted
    },
    branding: {
      logo_url: logoUrl,
      primary_color: primaryColor,
      company_name: companyName,
      brand_voice: brandVoice
    },
    system_prompt: systemPrompt
  }
}];

